import { useState, useEffect } from 'react';

export default function Loader() {
  const [stage, setStage] = useState('loading'); // loading → done → hidden

  useEffect(() => {
    const t1 = setTimeout(() => setStage('done'), 1800);
    const t2 = setTimeout(() => setStage('exit'), 2300);
    const t3 = setTimeout(() => setStage('hidden'), 2600);

    return () => {
      clearTimeout(t1);
      clearTimeout(t2);
      clearTimeout(t3);
    };
  }, []);

  if (stage === 'hidden') return null;

  return (
    <div className={`loader ${stage}`}>
      <div className="loader-content">
        <h1 className="loader-name">NIHAL</h1>
        <div className="loader-bar">
          <div className="loader-progress" />
        </div>
      </div>
    </div>
  );
}
